@Service
public class QuestionService {
    private final Counter questionsGenerated;
    private final Timer generationTimer;

    public QuestionService(MeterRegistry registry) {
        this.questionsGenerated = registry.counter("questions.generated",
            "source", "llm");
        this.generationTimer = registry.timer("questions.generation.duration");
    }

    public Question generate(ConceptId id, Level level) {
        return generationTimer.record(() -> {
            Question q = llmClient.generate(id, level);
            questionsGenerated.increment();
            return q;
        });
    }
}

